5299	// parseProviderConnectivityFacts extracts the actionable route facts —
5300	// the dialed endpoint URL and the transport timeout class — from a provider
5301	// connectivity failure report. Both returns are best-effort: an empty string
5302	// means the corresponding fact could not be parsed from Detail/Error/Stderr.
5303	func parseProviderConnectivityFacts(report ExecuteBeadReport) (endpoint, timeoutClass string) {
5304		combined := strings.Join([]string{
5305			report.Detail,
5306			report.Error,
5307			report.Stderr,
5308		}, "\n")
5309		endpoint = strings.TrimSpace(providerEndpointURLRe.FindString(combined))
5310		lower := strings.ToLower(combined)
5311		for _, marker := range timeoutClassMarkers {
5312			if strings.Contains(lower, marker) {
5313				timeoutClass = marker
5314				break
5315			}
5316		}
5317		return endpoint, timeoutClass
