5383	// normalizeFailedRoutes collapses duplicate (provider, model) entries keeping
5384	// the newest At timestamp and summing counts, then caps the list at
5385	// failedRoutesMaxEntries by evicting oldest entries (FIFO). Used by
5386	// readFailedRoutes to transparently migrate legacy bead data on read.
5387	func normalizeFailedRoutes(entries []FailedRouteEntry) []FailedRouteEntry {
5388		if len(entries) == 0 {
5389			return entries
5390		}
5391		type key struct{ provider, model string }
5392		index := make(map[key]int, len(entries))
5393		collapsed := make([]FailedRouteEntry, 0, len(entries))
5394		for _, e := range entries {
5395			k := key{e.Provider, e.Model}
5396			if i, ok := index[k]; ok {
5397				existingCount := collapsed[i].Count
5398				if existingCount == 0 {
5399					existingCount = 1
5400				}
5401				ec := e.Count
5402				if ec == 0 {
5403					ec = 1
5404				}
5405				if e.At > collapsed[i].At {
5406					endpoint := e.Endpoint
5407					if endpoint == "" {
5408						endpoint = collapsed[i].Endpoint
5409					}
5410					timeoutClass := e.TimeoutClass
5411					if timeoutClass == "" {
5412						timeoutClass = collapsed[i].TimeoutClass
5413					}
5414					collapsed[i] = FailedRouteEntry{
5415						Provider:     e.Provider,
5416						Model:        e.Model,
5417						ActualPower:  e.ActualPower,
5418						Reason:       e.Reason,
5419						Endpoint:     endpoint,
5420						TimeoutClass: timeoutClass,
5421						At:           e.At,
5422						Count:        existingCount + ec,
5423					}
5424				} else {
5425					collapsed[i].Count = existingCount + ec
5426					if collapsed[i].Endpoint == "" {
5427						collapsed[i].Endpoint = e.Endpoint
5428					}
5429					if collapsed[i].TimeoutClass == "" {
5430						collapsed[i].TimeoutClass = e.TimeoutClass
5431					}
5432				}
5433			} else {
5434				index[k] = len(collapsed)
5435				c := e
5436				if c.Count == 0 {
5437					c.Count = 1
5438				}
5439				collapsed = append(collapsed, c)
5440			}
5441		}
5442		if len(collapsed) > failedRoutesMaxEntries {
5443			collapsed = collapsed[len(collapsed)-failedRoutesMaxEntries:]
5444		}
5445		return collapsed
5446	}
